<script>
function wcdError(m){$('.isi_warning_delete').text(m||<?=prod_js('production_work_center_process_failed', 'Work Center Dashboard failed to process.');?>);$('.error_data_delete').fadeIn();}
function wcdFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),plant:$('#filter_plant').val(),operation_status:$('#filter_operation_status').val(),keyword:$('#filter_keyword').val()};}
function wcdQuery(){return $.param(wcdFilters());}
$(function(){if($.fn.datepicker){$('.wcd-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_plant,#filter_operation_status').select2({width:'100%',allowClear:true});}
var dt=$('#dtb_work_center_dashboard').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=prod_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{targets:[4,5],className:'text-right'},{width:'38px',targets:0},{width:'58px',targets:1}],ajax:{url:'<?=base_admin();?>modul/work_center_dashboard/work_center_dashboard_data.php',type:'post',data:function(d){$.extend(d,wcdFilters());},error:function(xhr){console.log(xhr.responseText);wcdError(<?=prod_js('production_work_center_load_failed', 'Work center data failed to load.');?>);}}});
$('#btn_filter_wcd').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_wcd').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_plant,#filter_operation_status').val('').trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_excel_wcd,#btn_excel_wcd_top').click(function(){window.location='<?=base_admin();?>modul/work_center_dashboard/work_center_dashboard_action.php?act=excel&'+wcdQuery();});
$(document).on('click','.btn-wcd-detail',function(){var wc=$(this).data('wc'),data=wcdFilters();data.work_center=wc;$.post('<?=base_admin();?>modul/work_center_dashboard/work_center_dashboard_action.php?act=detail',data,function(html){$('#wcd_detail_body').html(html);$('#modal_detail_wcd').modal('show');}).fail(function(){wcdError('Detail queue gagal dibuka.');});});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
</script>
